import Link from "next/link";
import { Tag, MapPin, Calendar, ChevronRight, Inbox } from "lucide-react";

const WideCard = ({ item }) => {
  const getStatusColor = (status) => {
    switch (status?.toLowerCase()) {
      case "pending":
        return "text-amber-500 bg-amber-50 border-amber-100";
      case "accepted":
        return "text-emerald-500 bg-emerald-50 border-emerald-100";
      default:
        return "text-indigo-500 bg-indigo-50 border-indigo-100";
    }
  };

  return (
    <div className="group relative w-full mb-6 max-w-5xl mx-auto">
      {/* Main Card */}
      <div className="flex items-center bg-white border border-gray-100 rounded-3xl p-4 shadow-sm hover:shadow-xl hover:border-indigo-100 transition-all duration-300">
        {/* 1. Image Section - Fixed Square */}
        <div className="relative h-32 w-32 md:h-40 md:w-40 flex-shrink-0 overflow-hidden rounded-2xl shadow-inner">
          <img
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
            src={item.photos?.[0] || "https://placehold.co/400?text=No+Photo"}
            alt={item.itemName}
          />
        </div>

        {/* 2. Content Section - Flex Grow */}
        <div className="flex-grow px-6 md:px-10">
          <div className="flex items-center gap-3 mb-2">
            <h3 className="text-2xl font-black text-gray-800 tracking-tight leading-none">
              {item.itemName}
            </h3>
            <span
              className={`px-3 py-1 text-[10px] font-bold uppercase rounded-full border ${getStatusColor(item.status)}`}
            >
              {item.status}
            </span>
          </div>

          <div className="flex flex-wrap gap-y-2 gap-x-6">
            <div className="flex items-center text-sm text-gray-500 font-medium">
              <Tag className="w-4 h-4 mr-2 text-indigo-400" />
              {item.category || "General"}
            </div>
            <div className="flex items-center text-sm text-gray-500 font-medium">
              <MapPin className="w-4 h-4 mr-2 text-indigo-400" />
              {item.location}
            </div>
            <div className="flex items-center text-sm text-gray-500 font-medium">
              <Calendar className="w-4 h-4 mr-2 text-indigo-400" />
              {new Date(item.date).toLocaleDateString("en-GB")}
            </div>
          </div>
        </div>

        {/* 3. Actions Section - Right Aligned */}
        <div className="hidden md:flex flex-col gap-2 min-w-[160px] border-l border-gray-100 pl-8">
          <Link href={`/claimItem/${item._id}`}>
            <button className="w-full py-3 bg-indigo-600 hover:bg-black text-white rounded-2xl text-sm font-bold transition-all shadow-lg shadow-indigo-100 active:scale-95">
              Claim Now
            </button>
          </Link>
          <Link
            href={`/item/${item._id}`}
            className="text-center text-xs font-semibold text-gray-400 hover:text-indigo-600 transition-colors py-1"
          >
            View Details
          </Link>
        </div>

        {/* Mobile-only arrow for details */}
        <div className="md:hidden flex-shrink-0">
          <ChevronRight className="w-6 h-6 text-gray-300" />
        </div>
      </div>
    </div>
  );
};

export default WideCard;
